#[tokio::test]
async fn post_toggle_completes_a_pending_todo() {
    let app = spawn_app().await;
    let client = register_and_login(&app.address, "toggle@example.com", "securepassword123").await;

    // Add a todo
    client
        .post(format!("{}/todos", &app.address))
