     1→/**
     2→ * Todo list focus management and empty state -- progressive enhancement for HTMX.
     3→ *
     4→ * Focus management:
     5→ * After an HTMX delete swap removes a todo item from the DOM, focus
     6→ * would otherwise be lost (sent to <body>). This script moves focus
     7→ * to the logical next element:
     8→ *   1. Next sibling todo item (if one exists)
     9→ *   2. Previous sibling todo item (if deleted was last in list)
    10→ *   3. The "New todo" input (if the list is now empty)
    11→ *
    12→ * Empty state transitions:
    13→ * When the last item is deleted, shows the "No todos yet." message
    14→ * and hides the empty list. When the first item is added to an empty
    15→ * list, hides the message and shows the list.
    16→ *
    17→ * A11y: Focus management after DOM removal is required by WCAG 2.4.3
    18→ * (Focus Order) and is part of our HTMX Focus Management Protocol.
    19→ */
    20→(function () {
    21→  "use strict";
    22→
    23→  // Track the focus target before the swap removes the element
    24→  var pendingFocusTarget = null;
    25→  var pendingDeleteSwap = false;
    26→
    27→  document.body.addEventListener("htmx:beforeSwap", function (e) {
    28→    var target = e.detail.target;
    29→
    30→    // Only handle delete swaps (empty response that removes an element)
    31→    if (!target || !target.classList || !target.classList.contains("todo-item")) {
    32→      return;
    33→    }
    34→
    35→    // If the response body is empty, this is a delete operation
    36→    var responseText = e.detail.xhr ? e.detail.xhr.responseText : "";
    37→    if (responseText.trim() !== "") {
    38→      return;
    39→    }
    40→
    41→    pendingDeleteSwap = true;
    42→
    43→    // Determine focus target before the element is removed
    44→    var nextItem = target.nextElementSibling;
    45→    var prevItem = target.previousElementSibling;
    46→
    47→    if (nextItem && nextItem.classList.contains("todo-item")) {
    48→      pendingFocusTarget = nextItem;
    49→    } else if (prevItem && prevItem.classList.contains("todo-item")) {
    50→      pendingFocusTarget = prevItem;
    51→    } else {
    52→      // List will be empty after this deletion -- focus the add input
    53→      pendingFocusTarget = document.getElementById("title");
    54→    }
    55→  });
    56→
    57→  document.body.addEventListener("htmx:afterSettle", function () {
    58→    // Handle empty state visibility after delete
    59→    if (pendingDeleteSwap) {
    60→      pendingDeleteSwap = false;
    61→      updateEmptyState();
    62→    }
    63→
    64→    if (!pendingFocusTarget) {
    65→      return;
    66→    }
    67→
    68→    var el = pendingFocusTarget;
    69→    pendingFocusTarget = null;
    70→
    71→    // Make the target focusable if it isn't already
    72→    if (!el.hasAttribute("tabindex") && el.tagName !== "INPUT" && el.tagName !== "BUTTON" && el.tagName !== "A") {
    73→      el.setAttribute("tabindex", "-1");
    74→    }
    75→
    76→    el.focus();
    77→  });
    78→
    79→  // After adding a todo, hide empty state and show the list
    80→  document.body.addEventListener("htmx:afterRequest", function (e) {
    81→    var elt = e.detail.elt;
    82→    // Only handle the add-todo form's successful POST
    83→    if (!elt || !elt.classList || !elt.classList.contains("todo-add")) {
    84→      return;
    85→    }
    86→    if (!e.detail.successful) {
    87→      return;
    88→    }
    89→    updateEmptyState();
    90→  });
    91→
    92→  function updateEmptyState() {
    93→    var todoList = document.querySelector(".todo-list");
    94→    var emptyMsg = document.getElementById("todo-empty");
    95→    if (!todoList || !emptyMsg) {
    96→      return;
    97→    }
    98→
    99→    var hasItems = todoList.querySelector(".todo-item") !== null;
   100→
   101→    if (hasItems) {
   102→      todoList.removeAttribute("hidden");
   103→      emptyMsg.setAttribute("hidden", "");
